fun solve(n: Long): String {
    val nSquared = n * n
    val nCubed = n * n * n

    val hexDigits = "0123456789ABCDEF"
    var hexStr = ""
    if (nSquared == 0L) {
        hexStr = "0"
    } else {
        var temp = nSquared
        while (temp > 0) {
            hexStr = hexDigits[(temp % 16).toInt()] + hexStr
            temp /= 16
        }
    }

    val base36Digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
    var base36Str = ""
    if (nCubed == 0L) {
        base36Str = "0"
    } else {
        var temp = nCubed
        while (temp > 0) {
            base36Str = base36Digits[(temp % 36).toInt()] + base36Str
            temp /= 36
        }
    }

    return hexStr + base36Str
}
